</template>

<script>
import { mapState } from 'vuex';

export default {
    computed: {
        ...mapState({
            boxText: state => state.home.boxText,

            mediaFistNews: state => state.home.mediaFistNews,
            mediaFist: state => state.home.mediaFist,
            media: state => state.list.contents,

            update: state => state.home.update
        }),
        twoMedia() {
            return this.media.slice(this.start, this.end);
        }
    },
    data() {
        return {
            start: 0,
            end: 2,
            // ----- ----- ----- ----- ----- ----- -----
            leftBox: "Main Title",
            mediaTitle: "Media News",
            updateTitle: "Update",
