                    <transition name="fade" mode="out-in">
                        <ul class="sub-menu" v-if="isSubMenuVisible">
                            <li class="sub-li" v-for="item in subMenuItems1" :key="item.text"><router-link class="action"
                                    :to="item.to">{{ item.text }}</router-link></li>
