</template>

<script>
import { mapState } from 'vuex';

export default {
    computed: {
        ...mapState({
            menuItems: state => state.nav.menuItems,
            subMenuItems1: state => state.nav.subMenuItems1,
            subMenuItems2: state => state.nav.subMenuItems2,
            subMenuItems3: state => state.nav.subMenuItems3,
            subMenuItems4: state => state.nav.subMenuItems4,
            subMenuItems5: state => state.nav.subMenuItems5,
            
        })
    },
    data() {
        return {
            isSubMenuVisible: Array.from({ length: 7 }, () => false),
        };
    },
    methods: {
        showSubMenu() {
            this.isSubMenuVisible = true;
        },
        hideSubMenu() {
            this.isSubMenuVisible = false;
        }
    }
};
</script>

