<template>
    <!-- 首页新闻图片布局 -->
    <div id="news-picture">
        <div id="news-ul" :style="{ left: leftPosition }">
            <div class="news-li" v-for="(item, index) in url" :key="index">
                <img :src="url[index]" alt="这是首页新闻图片">
            </div>
        </div>
        <button id="news-left" @click="prevSlide"></button>
        <button id="news-right" @click="nextSlide"></button>
    </div>

    <!-- 首页新闻图片的下标 -->
    <div id="news-nav">
        <span v-for="(item, index) in url" :key="index" :class="['nav-dot', { 'spanChoosing': currentPage === index }]"
            @click="changePage(index)"></span>
    </div>

    <topInfo />
    <activityInfo />
    <campsInfo />
    <teacherInfo />
    <partnerInfo />
</template>

<script>
import topInfo from "../components/homePage/topInfo.vue";
import activityInfo from "../components/homePage/activityInfo.vue";
import campsInfo from "../components/homePage/campsInfo.vue";
import teacherInfo from "../components/homePage/teacherInfo.vue";
import partnerInfo from "../components/homePage/partnerInfo.vue";
import { mapState } from 'vuex';

export default {
    components: {
        topInfo,
        activityInfo,
        campsInfo,
        teacherInfo,
        partnerInfo
    },
    data() {
        return {
            currentPage: 0,
            timer: null,
        }
    },
    methods: {
        prevSlide() {
            if (this.currentPage > 0) {
                this.currentPage--;
            } else {
                this.currentPage = this.url.length - 1;
            }
            this.resetTimer();
        },
        nextSlide() {
            if (this.currentPage < this.url.length - 1) {
                this.currentPage++;
            } else {
                this.currentPage = 0;
            }
            this.resetTimer();
        },
        startTimer() {
            this.timer = setInterval(() => {
                this.nextSlide();
            }, 7000);
        },
        resetTimer() {
            clearInterval(this.timer);
            this.startTimer();
        },
    },
    computed: {
        ...mapState({
            url: state => state.home.url,
        }),

        leftPosition() {
            return -this.currentPage * 100 + "%";
        },
    },
    mounted() {
        this.startTimer();
    },
    beforeUnmount() {
        clearInterval(this.timer);
    },
}
</script>

<style scoped>
#news-picture {
    width: 100%;
    height: 360px;
    background-color: white;
    overflow: hidden;
    position: relative;
}

#news-ul {
    width: 100%;
    height: 100%;
    display: flex;
    position: absolute;
    transition: left 0.5s ease;
}

.news-li {
    flex: 0 0 100%;
    height: 100%;
    transition: left 1s ease;
    display: flex;
}

.news-li img {
    width: 100%;
    object-fit: cover;
}

#news-picture button {
    position: absolute;
    width: 100px;
    height: 100%;
    border: 0;
    background-color: #dcdcdc50;
    background-position: center;
    background-repeat: no-repeat;
    padding: 0 50px;
    box-sizing: border-box;

}

#news-left {
    background-image: url(@/assets/home/icon/icons/left.png);
    left: 0;
}

#news-right {
    background-image: url(@/assets/home/icon/icons/right.png);
    right: 0;
}

/* ---------- ---------- ---------- ---------- ---------- */

#news-nav {
    position: relative;
    width: 100%;
    height: 20px;
    margin-top: 20px;
    margin-bottom: 50px;
    display: flex;
    justify-content: center;
}

#news-nav span {
    width: 10px;
    height: 10px;
    border-radius: 20px;
    margin: 0 5px;
    box-shadow: 2px 2px 4px lightgray, -2px -2px 4px lightgray;
}

.spanChoosing {
    background-color: lightpink;
    transform: scale(1.5);
}
</style>

<!-- 共同属性 -->
<style>
.content {
    padding: 0 30px;
    box-sizing: border-box;
    margin-top: 50px;
    width: 100%;
}

.content-top {
    position: relative;
    width: 100%;
    font-size: 24px;
    margin-bottom: 30px;
}

.content-top p {
    text-shadow: 1px 1px 1px lightblue;
    cursor: default;
    margin-left: 2em;
    display: inline-block;
    position: relative;
    height: 100%;
    padding-bottom: 5px;
    border-bottom: 2px solid orange;
}

.content-top button {
    border: 0;
    background-color: transparent;
    display: inline-block;
    position: relative;
    color: gray;
    margin-right: 1em;
    height: 100%;
    font-size: 26px;
    padding-bottom: 5px;
}

.content-top button:last-child {
    margin-right: 3em;
}

.content-top button:hover {
    border-bottom: 2px solid orange;
    color: orange;
}

.content .title-line {
    box-shadow: -1px 0px 1px lightgray;
    position: absolute;
    margin-left: 2em;
    width: calc(100% - 5em);
    height: 2px;
    bottom: 0;
    z-index: -1;
    background-color: gainsboro;
    box-sizing: content-box;
}

.content-content {
    width: 100%;
    margin: 50px 0;
    height: auto;
}

.content-content ul {
    display: flex;
    flex-direction: row;
    flex-wrap: wrap;
    width: 100%;
    height: 100%;
}

h3 {
    text-shadow: 1px 1px 1px lightblue;
}
</style>