import { createRouter, createWebHistory } from "vue-router";
import homePage from "@/views/homePage.vue";
import newsPage from "@/views/newsPage.vue"
import activitiesPage from "@/views/subNewsPage/activitiesPage.vue";
import aboutPage from "@/views/aboutPage.vue";
import advantagePage from "@/views/subAboutPage/advantagePage.vue"
import contactPage from "@/views/contactPage.vue"
import applicationPage from "@/views/subContactPage/applicationPage.vue"
// import galleriesPage from "@/views/galleriesPage.vue";

const routes = [
  {
    path: "/",
    name: "home",
    component: homePage,
  },
  // ----- ----- ----- ----- ----- ----- -----
  // {
  //   path: '/program',
  //   name: 'program',
  //   component: aboutPage,
  // },
  // ----- ----- ----- ----- ----- ----- -----
  {
    path: '/news',
    name: 'news',
    component: newsPage,
  },
  {
    path: "/activities",
    name: "activities",
    component: activitiesPage
  },
  // ----- ----- ----- ----- ----- ----- -----
  // {
  //   path: '/learning',
  //   name: 'learning',
  //   component: aboutPage,
  // },
  // ----- ----- ----- ----- ----- ----- -----
  // {
  //   path: '/galleries',
  //   name: 'galleries',
  //   component: galleriesPage,
  // },
  // ----- ----- ----- ----- ----- ----- -----
  {
    path: '/contact',
    name: 'contact',
    component: contactPage,
  },
  {
    path: '/application',
    name: 'application',
    component: applicationPage,
  },
  // ----- ----- ----- ----- ----- ----- -----
  {
    path: "/about",
    name: "about",
    component: aboutPage,
  },
  {
    path: "/advantage",
    name: "advantage",
    component: advantagePage,
  },
];

const router = createRouter({
  history: createWebHistory(process.env.BASE_URL),
  routes,
});

export default router;
