<template>
    <div id="partners" class="content">
        <div class="content-top">
            <p>{{ boxTitle }}</p>
            <div style="float: right">
                <button>More...</button>
            </div>
            <div class="title-line"></div>
        </div>
        <div class="content-content">
            <ul>
                <li v-for="(item, index) in partners" :key="index" ref="partnersLi">
                    {{ item.text }}
                </li>
            </ul>
        </div>
    </div>
</template>
  
<script>
export default {
    data() {
        return {
            boxTitle: "Partners",
            partners: [
                { text: "Partner 1" },
                { text: "Partner 2" },
                { text: "Partner 3" },
                { text: "Partner 4" },
            ],
        };
    },
    mounted() {
        const partnersLi = this.$refs.partnersLi;

        partnersLi.forEach((li, index) => {
            if (index % 2 === 0) {
                li.style.background = "wheat";
                li.textContent = "Text Area";
            } else {
                li.style.background = "lightgray";
                li.textContent = "Picture Area";
            }
        });
    },
};
</script>

<style scoped>
#partners .content-content {
    box-sizing: content-box;
    margin: 0 auto;
    margin-bottom: 50px;
    width: calc(100% - 200px);
    height: 100px;
}

#partners .content-content ul {
    display: flex;
    justify-content: center;
    align-items: center;
    height: 100%;
    width: 100%;
}

#partners .content-content li {
    background-color: red;
    margin: 0 auto;
    width: 250px;
    height: 100%;
    background-color: wheat;
    border-radius: 5px;
}
</style>