<template>
    <div id="newsWindows">
        <div :style="{ display: showDetails === true ? 'block' : 'none' }" id="newsTopNav">
            <button @click="backChange">&lt;&nbsp;back</button>
        </div>
        <div :style="{ display: showDetails === false ? 'block' : 'none' }" id="simpleContent">
            <ul id="newsContent">
                <li v-for="(item, index) in currentPageContents" :key="index">
                    <div class="showSwitch">
                        <div class="thumbnail">
                            <img :src="item.contentImage" alt="">
                        </div>
                        <div class="textContent">
                            <h3>{{ item.contentTitle }}</h3>
                            <p class="textContentText">{{ item.contentText }}</p>
                            <p class="textContentDate">{{ item.contentDate }}</p>
                            <button @click="changeEnter(item.contentComponent)">More Details</button>
                        </div>
                    </div>
                </li>
            </ul>

            <div class="pagination">
                <button id="prevPage" :style="{ visibility: currentPage > 1 ? 'visible' : 'hidden' }"
                    :disabled="currentPage === 1" @click="prevPage">Prev Page</button>
                <span id="pageNumber">{{ currentPage }}</span>
                <button id="nextPage" :style="{ visibility: currentPage < totalPages ? 'visible' : 'hidden' }"
                    :disabled="currentPage === totalPages" @click="nextPage">Next Page</button>
            </div>
        </div>
        <div id="courseProgram">
            <component :is="currentDetailComponent" v-if="showDetails" />
        </div>
    </div>
</template>

<script>
import courseProgram from "../components/newsPage/adultEnglish.vue";
import childEnglish from "../components/newsPage/childEnglish.vue";
import demoPage from "../components/newsPage/demoPage.vue";
import { mapState } from "vuex";

export default {
    components: {
        courseProgram,
        demoPage,
        childEnglish
    },
    data() {
        return {
            // 每页显示的内容数
            contentsPerPage: 7,
            // 当前页数
            currentPage: 1,
            // 组件展示
            // 显示与隐藏
            showDetails: false,
            currentDetailComponent: null,
        }
    },
    computed: {
        ...mapState({
            contents: state => state.list.contents
        }),
        totalPages() {
            return Math.ceil(this.contents.length / this.contentsPerPage);
        },
        currentPageContents() {
            const startIndex = (this.currentPage - 1) * this.contentsPerPage;
            const endIndex = startIndex + this.contentsPerPage;
            return this.contents.slice(startIndex, endIndex);
        },
    },
    methods: {
        // 传输数据
        updata(newData) {
            this.$emit('update:title', newData)
        },
        backChange() {
            this.showDetails = !this.showDetails;
        },
        changeEnter(componentName) {
            if (componentName) {
                this.showDetails = !this.showDetails;
                this.currentDetailComponent = componentName;
            }
            
            window.scrollTo({
                top: 200,
                left: 0,
                behavior: 'smooth'
            });
        },
        prevPage() {
            if (this.currentPage > 1) {
                this.currentPage--;
            }
        },
        nextPage() {
            if (this.currentPage < this.totalPages) {
                this.currentPage++;
            }
        }
    },
}
</script>

<style scoped>
#newsTopNav {
    margin-top: 20px;
    width: 100%;
    height: 30px;
}


#newsTopNav button {
    border: 0;
    background: lightgray;
    height: 100%;
    width: 80px;
    border-radius: 50px;
    font-size: 20px;
}

/* ----- ----- ----- ----- ----- ----- ----- */

#courseProgram {
    width: 100%;
}

#simpleContent {
    width: 100%;
    height: 100%;
}

/* ----- ----- ----- ----- ----- ----- ----- */

#newsWindows {
    width: 100%;
    padding: 0 150px;
    box-sizing: border-box;
}

#newsWindows ul {
    width: 100%;
    height: auto;
    position: relative;
}

#newsWindows li {
    width: 100%;
    height: 170px;
    background-color: white;
    border-bottom: 1px solid gainsboro;
    box-shadow: 2px 3px 5px gainsboro;
    margin: 20px 0;
}


#newsWindows li img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.pagination span {
    font-size: 18px;
    font-weight: 900;
    margin-bottom: 50px;
}

.pagination {
    text-align: center;
}

.pagination button {
    display: inline-block;
    border: 0;
    background-color: transparent;
    padding: 10px 0;
    font-size: 16px;
    font-weight: 900;
    margin: 0 10px;
    color: gray;
}

.pagination button:hover {
    color: orange;
}

.showSwitch {
    width: 100%;
    height: 100%;
    display: flex;
}

.thumbnail {
    position: relative;
    height: 100%;
    width: 300px;
    background-color: aliceblue;
}

.textContent {
    height: 100%;
    flex: 1;
    margin-left: 30px;
    padding: 20px;
    box-sizing: border-box;
    position: relative;
}

.textContent h3 {
    font-size: 20px;
}

.textContent .textContentText {
    margin-top: 20px;
    font-size: 14px;
}

.textContent .textContentDate {
    position: absolute;
    left: 20px;
    bottom: 20px;
}

.textContent button {
    position: absolute;
    border: 0;
    padding: 5px 10px;
    bottom: 20px;
    right: 20px;
    background-color: orange;
}
</style>